// Sem @State — isso NÃO compila:
struct ContadorView: View {
    var contador = 0  // struct não pode mutar

    var body: some View {
        Button("\(contador)") {
            contador += 1  // ERRO: Cannot assign to property: 'self' is immutable
        }
    }
}

// Com @State — funciona corretamente:
struct ContadorView: View {
    @State private var contador = 0  // armazenado fora da struct

    var body: some View {
        Button("\(contador)") {
            contador += 1  // muta o armazenamento externo, View é recriada
        }
    }
}

// Correto — @State como estado interno privado:
struct FormularioView: View {
    @State private var nome = ""
    @State private var emailValido = false
    @State private var mostrarErro = false

    var body: some View {
        VStack {
            TextField("Nome", text: $nome)
            if mostrarErro {
                Text("Nome inválido").foregroundStyle(.red)
            }
            Button("Salvar") {
                mostrarErro = nome.count < 3
            }
        }
    }
}

// View pai — tem o @State:
struct AppView: View {
    @State private var mostrarModal = false

    var body: some View {
        VStack {
            BotaoAbrirModal(aberto: $mostrarModal)  // $ passa o Binding
            if mostrarModal {
                Text("Modal aberto!")
            }
        }
    }
}

// View filha — recebe @Binding:
struct BotaoAbrirModal: View {
    @Binding var aberto: Bool  // referência ao @State da pai

    var body: some View {
        Button("Abrir") {
            aberto = true  // escreve diretamente no @State da pai
        }
    }
}

