// @Observable — forma moderna:
@Observable
class SessaoUsuario {
    var usuarioLogado: Usuario?  // @Observable rastreia automaticamente
    var tema: Tema = .claro
    var notificacoesAtivas = true

    func fazerLogin(email: String, senha: String) async throws {
        usuarioLogado = try await AuthService.login(email: email, senha: senha)
    }

    func fazerLogout() {
        usuarioLogado = nil
    }
}

// ObservableObject — forma legada (iOS 13-16), mais verbosa:
class SessaoUsuarioLegada: ObservableObject {
    @Published var usuarioLogado: Usuario?  // cada propriedade precisa de @Published
    @Published var tema: Tema = .claro
}

// A View raiz cria e é dona do objeto:
struct AppView: View {
    @State private var sessao = SessaoUsuario()  // @State pois View é dona

    var body: some View {
        ContentView()
            .environment(sessao)  // injeta para toda a hierarquia
    }
}

// View filha acessa via @Environment:
struct PerfilView: View {
    @Environment(SessaoUsuario.self) private var sessao  // acessado de qualquer nível

    var body: some View {
        if let usuario = sessao.usuarioLogado {
            Text("Olá, \(usuario.nome)")
        }
    }
}

// Passagem direta (sem environment) quando existe hierarquia simples:
struct ItemView: View {
    let sessao: SessaoUsuario  // sem property wrapper

    var body: some View {
        Text(sessao.usuarioLogado?.nome ?? "Sem usuário")
    }
}

// Lendo valores do sistema:
struct TemaView: View {
    @Environment(\.colorScheme) private var esquema
    @Environment(\.horizontalSizeClass) private var tamanho
