// O que você escreve:
struct Contador: View {
    @State private var valor = 0
    var body: some View {
        Button("\(valor)") { valor += 1 }
    }
}

// O que o compilador gera (aproximado):
struct Contador: View {
    private var _valor = State(initialValue: 0)  // gerado pelo @State
    private var valor: Int {
        get { _valor.wrappedValue }              // lê do nodo
        nonmutating set { _valor.wrappedValue = newValue }  // escreve no nodo
    }
    var body: some View {
        Button("\(valor)") { valor += 1 }
    }
}
// A struct é recriada com 'initialValue: 0' a cada render
// Mas 'wrappedValue' aponta para o valor real no nodo — pode ser 42!

// INTENÇÃO: passar um valor inicial para o @State
struct Contador: View {
    @State private var valor: Int

    init(valorInicial: Int = 0) {
        _valor = State(initialValue: valorInicial)  // só muda o initialValue!
    }

    var body: some View {
        Button("\(valor)") { valor += 1 }
    }
}

// PROBLEMA: Se o pai mudar valorInicial depois que o Contador está na tela:
struct PaiView: View {
    @State private var base = 0

    var body: some View {
        Contador(valorInicial: base)  // mudar base NÃO atualiza o contador!
        Button("Mudar base") { base = 10 }  // base muda, contador permanece igual
    }
}

// SE VOCÊ QUER reagir a valores externos → use Binding ou Observable:
struct Contador: View {
    @Binding var valor: Int  // lê e escreve no @State do pai
    var body: some View {
        Button("\(valor)") { valor += 1 }
    }
}

@Observable
final class ConfiguracaoVM {
    var nome = ""
    var notificacoesAtivas = true
}

// ERRADO: Observable sem property wrapper não tem $:
struct FormularioView: View {
    var vm: ConfiguracaoVM

    var body: some View {
        TextField("Nome", text: $vm.nome)  // ERRO: 'vm' não é um property wrapper
    }
}

// CORRETO: @Bindable cria o $ para Observable:
struct FormularioView: View {
    @Bindable var vm: ConfiguracaoVM  // adiciona suporte ao $

    var body: some View {
        TextField("Nome", text: $vm.nome)           // funciona!
        Toggle("Notificações", isOn: $vm.notificacoesAtivas)  // funciona!
    }
}

// Também pode ser usado inline sem property wrapper:
struct FormularioView: View {
    var vm: ConfiguracaoVM

    var body: some View {
        TextField("Nome", text: Bindable(vm).nome)  // inline
    }
}

@Observable final class Modelo { var valor = 0 }

// Propriedade comum — só leitura, sem wrapper:
struct DisplayView: View {
    var modelo: Modelo  // lê sem precisar de wrapper
    var body: some View {
        Text("\(modelo.valor)")
    }
}

// @State — View é dona do objeto:
struct RaizView: View {
    @State private var modelo = Modelo()  // lifetime acoplado a essa View
    var body: some View {
        DisplayView(modelo: modelo)
    }
}

// @Bindable — precisa de Binding para propriedades do objeto:
struct EditarView: View {
    @Bindable var modelo: Modelo  // vem de fora, mas precisa de $
    var body: some View {
        Stepper("\(modelo.valor)", value: $modelo.valor)  // $ funciona!
    }
}

struct MinhaView: View {
    @State private var contador = 0
    @State private var texto = ""

    var body: some View {
        // Diagnóstico — mostra o que causou o rerender:
        let _ = Self._printChanges()
        // Saída no console:
        // MinhaView: _contador changed.
        // MinhaView: _texto changed.
        // MinhaView: @self changed.

        VStack {
            Text("\(contador)")
            TextField("Digite", text: $texto)
            Button("+") { contador += 1 }
        }
    }
}

// Separar Views grandes em Views menores reduz rerenders:
// Se só o texto muda, uma View menor que só observa 'texto' é atualizada,
// não a View inteira.
struct DisplayContador: View {  // só renderiza quando contador muda
    let contador: Int
    var body: some View { Text("\(contador)") }
}

struct CampoTexto: View {     // só renderiza quando texto muda
    @Binding var texto: String
    var body: some View { TextField("Digite", text: $texto) }
}
